void
EmitIR::operator()(VarDecl* obj)
{
  // 创建全局变量或局部变量
  if (mCurFunc == nullptr) {
    // 全局变量
    auto gv = new llvm::GlobalVariable(
      mMod,
      self(obj->type),
      obj->type->qual.isConst,
      llvm::GlobalValue::ExternalLinkage,
      nullptr, // 初始值
      obj->name);

    if (obj->init) {
      // TODO: 处理全局变量初始化
    }

    obj->any = gv;
  } else {
    // 局部变量
    auto& irb = *mCurIrb;
    auto alloca = irb.CreateAlloca(self(obj->type), nullptr, obj->name);

    if (obj->init) {
      // 存储初始值
      auto initVal = self(obj->init);
      irb.CreateStore(initVal, alloca);
    }

    obj->any = alloca;
  }
}

